import pytest

from your_module import flatten_dict


def test_flatten_dict_happy_path_nested_dict():
    data = {
        "a": 1,
        "b": {
            "c": 2,
            "d": 3,
        },
    }

    result = flatten_dict(data)

    assert result == {
        "a": 1,
        "b.c": 2,
        "b.d": 3,
    }


def test_flatten_dict_deeply_nested_dict():
    data = {
        "a": {
            "b": {
                "c": {
                    "d": 4
                }
            }
        }
    }

    result = flatten_dict(data)

    assert result == {"a.b.c.d": 4}


def test_flatten_dict_with_custom_separator():
    data = {
        "user": {
            "name": "Alice",
            "address": {
                "city": "NYC"
            },
        }
    }

    result = flatten_dict(data, sep="_")

    assert result == {
        "user_name": "Alice",
        "user_address_city": "NYC",
    }


def test_flatten_dict_with_parent_key():
    data = {
        "a": 1,
        "b": {
            "c": 2,
        },
    }

    result = flatten_dict(data, parent_key="root")

    assert result == {
        "root.a": 1,
        "root.b.c": 2,
    }


def test_flatten_dict_empty_dict():
    assert flatten_dict({}) == {}


def test_flatten_dict_preserves_non_dict_values():
    data = {
        "a": None,
        "b": [1, 2, 3],
        "c": ("x", "y"),
        "d": "text",
        "e": 0,
        "f": False,
    }

    result = flatten_dict(data)

    assert result == {
        "a": None,
        "b": [1, 2, 3],
        "c": ("x", "y"),
        "d": "text",
        "e": 0,
        "f": False,
    }


def test_flatten_dict_nested_empty_dict_is_omitted():
    data = {
        "a": {},
        "b": 1,
    }

    result = flatten_dict(data)

    assert result == {
        "b": 1,
    }


def test_flatten_dict_empty_parent_key_behaves_like_default():
    data = {"a": {"b": 1}}

    result = flatten_dict(data, parent_key="")

    assert result == {"a.b": 1}


def test_flatten_dict_non_string_keys_are_supported():
    data = {
        1: {
            2: "value"
        }
    }

    result = flatten_dict(data)

    assert result == {"1.2": "value"}


def test_flatten_dict_top_level_non_dict_raises_attribute_error():
    with pytest.raises(AttributeError):
        flatten_dict(["not", "a", "dict"])


def test_flatten_dict_nested_mapping_like_object_is_not_flattened():
    class MappingLike:
        def __init__(self):
            self.value = 1

    obj = MappingLike()
    data = {"a": obj}

    result = flatten_dict(data)

    assert result == {"a": obj}


def test_flatten_dict_none_input_raises_attribute_error():
    with pytest.raises(AttributeError):
        flatten_dict(None)
